     1→#!/usr/bin/env node
     2→/**
     3→ * Gmail OAuth2 Authorization CLI
     4→ *
     5→ * Interactive command-line tool to authorize Gmail API access and obtain
     6→ * OAuth2 tokens (access token + refresh token).
     7→ *
     8→ * Usage:
     9→ *   npm run authorize:gmail
    10→ *   # or
    11→ *   tsx src/cli/authorize-gmail.ts
    12→ *
    13→ * @packageDocumentation
    14→ */
    15→
    16→import * as readline from 'readline';
    17→import * as fs from 'fs';
    18→import * as path from 'path';
    19→import { GmailClient } from '../gmail/gmail-client';
    20→import { loadEnvironment } from '../config/env';
    21→import { startOAuthCallbackServer } from './oauth-callback-server';
    22→
    23→// Load environment variables
    24→loadEnvironment();
    25→
    26→/**
    27→ * Prompt user for input via command line
    28→ */
    29→function prompt(question: string): Promise<string> {
    30→  const rl = readline.createInterface({
    31→    input: process.stdin,
    32→    output: process.stdout,
    33→  });
    34→
    35→  return new Promise((resolve) => {
    36→    rl.question(question, (answer) => {
    37→      rl.close();
    38→      resolve(answer.trim());
    39→    });
    40→  });
    41→}
    42→
    43→/**
    44→ * Extract port from redirect URI
    45→ */
    46→function extractPortFromUri(uri: string): number {
    47→  try {
    48→    const url = new URL(uri);
    49→    return parseInt(url.port) || 3000;
    50→  } catch {
    51→    return 3000;
    52→  }
    53→}
    54→
    55→/**
    56→ * Save tokens to a JSON file for later use
    57→ */
    58→function saveTokens(tokens: Record<string, unknown>, outputPath: string): void {
    59→  const tokensJson = JSON.stringify(tokens, null, 2);
    60→  fs.writeFileSync(outputPath, tokensJson, 'utf-8');
    61→  console.log(`\n✅ Tokens saved to: ${outputPath}`);
    62→}
    63→
    64→/**
    65→ * Main authorization flow
    66→ */
    67→async function main() {
    68→  console.log('==============================================');
    69→  console.log('Gmail OAuth2 Authorization Tool');
    70→  console.log('==============================================\n');
    71→
    72→  // Check environment variables
    73→  const clientId = process.env.GMAIL_CLIENT_ID;
    74→  const clientSecret = process.env.GMAIL_CLIENT_SECRET;
    75→  const redirectUri = process.env.GMAIL_REDIRECT_URI;
    76→
    77→  if (!clientId || !clientSecret || !redirectUri) {
    78→    console.error('❌ Error: Missing Gmail OAuth2 credentials in environment variables.\n');
    79→    console.error('Please set the following in your .env file:');
    80→    console.error('  - GMAIL_CLIENT_ID');
    81→    console.error('  - GMAIL_CLIENT_SECRET');
    82→    console.error('  - GMAIL_REDIRECT_URI\n');
    83→    console.error('See ENVIRONMENT.md for setup instructions.');
    84→    process.exit(1);
    85→  }
    86→
    87→  console.log('Environment variables loaded:');
    88→  console.log(`  Client ID: ${clientId.substring(0, 20)}...`);
    89→  console.log(`  Redirect URI: ${redirectUri}\n`);
    90→
    91→  // Create Gmail client
    92→  const client = new GmailClient({
    93→    clientId,
    94→    clientSecret,
    95→    redirectUri,
    96→  });
    97→
    98→  // Step 1: Start local callback server
    99→  console.log('Step 1: Starting Local OAuth Callback Server\n');
   100→
   101→  const port = extractPortFromUri(redirectUri);
   102→  const callbackPath = new URL(redirectUri).pathname;
   103→
   104→  // Start the callback server (this returns a promise that resolves when the callback is received)
   105→  const callbackPromise = startOAuthCallbackServer(port, callbackPath);
   106→
   107→  // Step 2: Generate authorization URL
   108→  console.log('Step 2: Open Authorization URL in Your Browser\n');
   109→  const authUrl = client.getAuthorizationUrl();
   110→
   111→  console.log('📋 Copy and paste this URL into your browser:\n');
   112→  console.log('─────────────────────────────────────────────');
   113→  console.log(authUrl);
   114→  console.log('─────────────────────────────────────────────\n');
   115→
   116→  console.log("This will open Google's consent page where you can:");
   117→  console.log('  1. Select which Google account to use');
   118→  console.log('  2. Review the permissions being requested');
   119→  console.log('  3. Grant access to your Gmail account');
   120→  console.log('  4. Click "Continue" - the code will be captured automatically!\n');
   121→
   122→  console.log('💡 TIP: After clicking "Continue", a success page will show in your browser');
   123→  console.log('        and the CLI will automatically continue.\n');
   124→
   125→  // Step 3: Wait for callback with authorization code
   126→  console.log('Step 3: Waiting for Authorization...\n');
   127→  console.log('⏳ Waiting for you to grant access in your browser...\n');
   128→
   129→  const callbackResult = await callbackPromise;
   130→
   131→  if (callbackResult.error || !callbackResult.code) {
   132→    console.error('\n❌ Error: OAuth callback failed');
   133→    console.error(`   ${callbackResult.error || 'No authorization code received'}\n`);
   134→    process.exit(1);
   135→  }
   136→
   137→  const code = callbackResult.code;
   138→  console.log('✅ Authorization code received!\n');
   139→
   140→  // Step 4: Exchange code for tokens
   141→  console.log('Step 4: Exchange Code for Tokens\n');
   142→  console.log('Exchanging authorization code for access and refresh tokens...');
   143→
   144→  try {
   145→    const tokens = await client.exchangeCodeForTokens(code);
   146→
   147→    console.log('\n✅ Successfully obtained OAuth2 tokens!\n');
   148→    console.log('Token details:');
   149→    console.log(`  Access Token: ${tokens.access_token?.substring(0, 20)}...`);
   150→    console.log(
