/**
 * OAuth2 Callback Server
 *
 * Temporary HTTP server that listens for OAuth2 redirect callbacks
 * and extracts the authorization code.
 *
 * @packageDocumentation
 */

import * as http from 'http';

/**
 * OAuth2 callback result
 */
export interface OAuthCallbackResult {
  /**
   * Authorization code from Google
   */
  code: string;

  /**
   * Any error that occurred during the callback
   */
  error?: string;
}

/**
 * Start a temporary HTTP server to handle OAuth2 callbacks
 *
 * The server listens on the specified port and path, waiting for Google
 * to redirect back with an authorization code. Once received, the server
 * automatically shuts down and returns the code.
 *
 * @param port - Port to listen on (default: 3000)
 * @param path - Callback path (default: /oauth2callback)
 * @param timeoutMs - Maximum time to wait for callback (default: 5 minutes)
 * @returns Promise that resolves with the authorization code
 */
export function startOAuthCallbackServer(
  port: number = 3000,
  path: string = '/oauth2callback',
  timeoutMs: number = 5 * 60 * 1000
): Promise<OAuthCallbackResult> {
  return new Promise((resolve, reject) => {
    let server: http.Server | null = null;
    let timeoutHandle: NodeJS.Timeout | null = null;

    // Cleanup function
    const cleanup = () => {
      if (timeoutHandle) {
        clearTimeout(timeoutHandle);
        timeoutHandle = null;
      }
      if (server) {
        server.close();
        server = null;
      }
    };

    // Success HTML page
    const successHtml = `
<!DOCTYPE html>
<html>
<head>
  <title>Authorization Successful</title>
  <style>
    body {
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
      display: flex;
      justify-content: center;
      align-items: center;
      height: 100vh;
      margin: 0;
      background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    }
    .container {
      background: white;
      padding: 3rem;
      border-radius: 1rem;
      box-shadow: 0 20px 60px rgba(0,0,0,0.3);
      text-align: center;
      max-width: 500px;
    }
    .checkmark {
      width: 80px;
      height: 80px;
      border-radius: 50%;
      display: block;
      stroke-width: 3;
      stroke: #4bb543;
      stroke-miterlimit: 10;
      margin: 0 auto 2rem;
      box-shadow: inset 0px 0px 0px #4bb543;
      animation: fill .4s ease-in-out .4s forwards, scale .3s ease-in-out .9s both;
    }
    .checkmark-circle {
      stroke-dasharray: 166;
      stroke-dashoffset: 166;
      stroke-width: 3;
      stroke-miterlimit: 10;
      stroke: #4bb543;
      fill: none;
      animation: stroke 0.6s cubic-bezier(0.65, 0, 0.45, 1) forwards;
    }
    .checkmark-check {
      transform-origin: 50% 50%;
      stroke-dasharray: 48;
      stroke-dashoffset: 48;
      animation: stroke 0.3s cubic-bezier(0.65, 0, 0.45, 1) 0.8s forwards;
    }
    @keyframes stroke {
      100% { stroke-dashoffset: 0; }
    }
    @keyframes scale {
      0%, 100% { transform: none; }
      50% { transform: scale3d(1.1, 1.1, 1); }
    }
    @keyframes fill {
      100% { box-shadow: inset 0px 0px 0px 40px #4bb543; }
    }
    h1 { color: #333; margin-bottom: 1rem; }
    p { color: #666; font-size: 1.1rem; line-height: 1.6; }
    .close-message {
      margin-top: 2rem;
      padding: 1rem;
      background: #f0f0f0;
      border-radius: 0.5rem;
      color: #555;
      font-size: 0.9rem;
    }
  </style>
</head>
<body>
  <div class="container">
    <svg class="checkmark" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 52 52">
      <circle class="checkmark-circle" cx="26" cy="26" r="25" fill="none"/>
      <path class="checkmark-check" fill="none" d="M14.1 27.2l7.1 7.2 16.7-16.8"/>
    </svg>
    <h1>✓ Authorization Successful!</h1>
    <p>Your Gmail account has been successfully connected.</p>
    <p>The authorization code has been sent to the CLI tool.</p>
    <div class="close-message">
      You can close this window and return to your terminal.
    </div>
  </div>
</body>
</html>
    `;

    // Error HTML page
    const errorHtml = (errorMsg: string) => `
<!DOCTYPE html>
<html>
<head>
  <title>Authorization Error</title>
  <style>
    body {
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
      display: flex;
      justify-content: center;
      align-items: center;
      height: 100vh;
      margin: 0;
      background: linear-gradient(135deg, #f093fb 0%, #f5576c 100%);
    }
    .container {
      background: white;
      padding: 3rem;
      border-radius: 1rem;
      box-shadow: 0 20px 60px rgba(0,0,0,0.3);
      text-align: center;
      max-width: 500px;
    }
    .error-icon {
      font-size: 4rem;
      color: #f5576c;
      margin-bottom: 1rem;
    }
    h1 { color: #333; margin-bottom: 1rem; }
    p { color: #666; font-size: 1.1rem; line-height: 1.6; }
    .error-message {
      margin-top: 1.5rem;
      padding: 1rem;
      background: #ffe0e0;
      border-left: 4px solid #f5576c;
      border-radius: 0.25rem;
      color: #721c24;
      font-family: monospace;
      font-size: 0.9rem;
      text-align: left;
    }
  </style>
</head>
<body>
  <div class="container">
    <div class="error-icon">⚠️</div>
    <h1>Authorization Error</h1>
    <p>There was a problem with the OAuth2 callback.</p>
    <div class="error-message">${errorMsg}</div>
    <p style="margin-top: 1.5rem;">Please return to your terminal and try again.</p>
  </div>
</body>
</html>
    `;

    // Create HTTP server
    server = http.createServer((req, res) => {
      // Only handle our callback path
      if (!req.url?.startsWith(path)) {
        res.writeHead(404);
        res.end('Not Found');
        return;
      }

      // Parse URL to get query parameters
      const url = new URL(req.url, `http://localhost:${port}`);
      const code = url.searchParams.get('code');
      const error = url.searchParams.get('error');

      if (error) {
        // OAuth error from Google
        const errorDescription = url.searchParams.get('error_description') || error;
        res.writeHead(200, { 'Content-Type': 'text/html' });
        res.end(errorHtml(errorDescription));
        cleanup();
        resolve({ code: '', error: errorDescription });
        return;
      }

      if (!code) {
        // Missing code parameter
        res.writeHead(200, { 'Content-Type': 'text/html' });
        res.end(errorHtml('Missing authorization code in callback'));
        cleanup();
        resolve({ code: '', error: 'Missing authorization code' });
        return;
      }

      // Success! We got the code
      res.writeHead(200, { 'Content-Type': 'text/html' });
      res.end(successHtml);
      cleanup();
      resolve({ code });
    });

    // Set timeout
    timeoutHandle = setTimeout(() => {
      cleanup();
      reject(new Error(`OAuth callback timeout after ${timeoutMs}ms`));
    }, timeoutMs);

    // Start listening
    server.listen(port, () => {
      console.log(`\n🌐 Local OAuth callback server started on http://localhost:${port}${path}`);
      console.log('   Waiting for Google to redirect back...\n');
    });

    // Handle server errors
    server.on('error', (err) => {
      cleanup();
      reject(err);
    });
  });
}

